<!DOCTYPE html>
<html>
<head>
  <meta charset="utf-8">
  <title>Kanban Board</title>
  <style>
    body { font-family: sans-serif; }

    #container {
      display: flex;
      height: 500px;
    }

    #col-todo, #col-doing, #col-done {
      width: 200px;
      border: 1px solid #ccc;
      margin: 10px;
      padding: 10px;
      min-height: 400px;
      overflow-y: auto;
    }

    .count {
      font-weight: bold;
      text-align: center;
      margin-bottom: 5px;
    }

    .card {
      background-color: #f2f2f2;
      border: 1px solid #ccc;
      padding: 10px;
      margin-bottom: 5px;
      cursor: grab;
      user-select: none;
    }

    .card-del {
      float: right;
      font-weight: bold;
      color: red;
      cursor: pointer;
      padding: 2px;
    }

    #new-card, #add-card {
      margin-right: 10px;
    }
  </style>
</head>
<body>
  <h1>Kanban Board</h1>

  <div id="container">
    <div id="col-todo" draggable="true">
      <span class="count">0</span>
      <div id="new-card">New Card</div>
      <button id="add-card">Add</button>
    </div>

    <div id="col-doing" draggable="true">
      <span class="count">0</span>
    </div>

    <div id="col-done" draggable="true">
      <span class="count">0</span>
    </div>
  </div>

  <script>
    const boardData = JSON.parse(localStorage.getItem('boardState') || '[]');
    let draggedCard = null;

    function updateBoardData() {
      localStorage.setItem('boardState', JSON.stringify(boardData));
    }

    function renderBoard() {
      const colTodo = document.getElementById('col-todo');
      const colDoing = document.getElementById('col-doing');
      const colDone = document.getElementById('col-done');
      const countElements = document.querySelectorAll('.count');
      const cardElements = document.querySelectorAll('.card');

      colTodo.innerHTML = '';
      colDoing.innerHTML = '';
      colDone.innerHTML = '';

      boardData.forEach((card, index) => {
        const cardElement = document.createElement('div');
        cardElement.classList.add('card');
        cardElement.draggable="true";
        cardElement.dataset.index = index; // Store the original index

        cardElement.textContent = card.title;
        cardElement.addEventListener('dragstart', (e) => {
          draggedCard = index;
          e.dataTransfer.effectAllowed = 'move';
          e.dataTransfer.setData('text/plain', index);
        });

        cardElement.addEventListener('dragover', (e) => {
          e.preventDefault();
        });

        cardElement.addEventListener('drop', (e) => {
          e.preventDefault();
          const column = e.target.id;
          let originalIndex = draggedCard;

          if(column === 'col-todo'){
            boardData[originalIndex] = { title: cardElement.textContent, column: 'todo' };
          } else if (column === 'col-doing') {
            boardData[originalIndex] = { title: cardElement.textContent, column: 'doing' };
          } else {
            boardData[originalIndex] = { title: cardElement.textContent, column: 'done' };
          }

          updateBoardData();
          renderBoard();
          draggedCard = null;
        });

        cardElement.addEventListener('dragend', (e) => {
          draggedCard = null;
        });

        cardElement.querySelector('.card-del').addEventListener('click', () => {
          boardData.splice(originalIndex, 1);
          updateBoardData();
          renderBoard();
        });


        if (card.column === 'todo') {
          colTodo.appendChild(cardElement);
        } else if (card.column === 'doing') {
          colDoing.appendChild(cardElement);
        } else {
          colDone.appendChild(cardElement);
        }

        updateCount(colTodo, boardData.filter(c => c.column === 'todo').length);
        updateCount(colDoing, boardData.filter(c => c.column === 'doing').length);
        updateCount(colDone, boardData.filter(c => c.column === 'done').length);
      });
    }

    function updateCount(element, count) {
      const countElement = element.querySelector('.count');
      if (countElement) {
        countElement.textContent = count;
      }
    }


    document.getElementById('add-card').addEventListener('click', () => {
      const cardText = document.getElementById('new-card').value;
      if (cardText) {
        boardData.push({ title: cardText, column: 'todo' });
        updateBoardData();
        renderBoard();
        document.getElementById('new-card').value = '';
        updateCount(document.getElementById('col-todo'), boardData.filter(c => c.column === 'todo').length);
      }
    });

    renderBoard();
  </script>
</body>
</html>
